def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 30.0 + np.cos(cap * 2.5) * 20 + np.log1p(cap * 7) * 15
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.3) - 300 * np.sin(cap * 3.1)
            if cap > 12:
                base_priority += np.cbrt(cap) * 150 + 50 * np.tan(cap / 7)
            else:
                base_priority -= 60 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** (i+1)) * np.cos(usage * np.pi * i * 0.9) * 25 / (i+1)
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 1.7 + 180 * (1 - delta ** 0.6)
            for j in range(1, 10):
                fluctuation += np.sin(usage * np.pi * (j ** 1.4)) * 30 / j
            if int(cap * 4) % 5 == 0:
                base_priority += 45 * np.tan(cap / 12)
        elif 3 < usage <= 4:
            base_priority += 1900 * (usage - 3.2)**2
            for k in range(1, 15):
                val = usage ** (k / 1.5)
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 15 / (k + 3)
                    if k == 12 and usage > 3.5:
                        fluctuation += 25
            if cap % 3.1 < 0.7:
                base_priority += 40 * np.sin(cap * 2.8)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2.5) ** 2.5
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 20 / m
                    if m % 2 == 1:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 2)
                    if m == 17 and usage > 2.7:
                        fluctuation += 18
            if cap % 1.7 < 0.6:
                base_priority += 38 * np.cos(cap * 3.4)
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1.4) ** 3
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.65:
                    fluctuation += pwr * 22 / n
                    if n % 5 == 2:
                        fluctuation -= 2.5 * n
                else:
                    fluctuation += (1 - pwr) * 10 / (n + 2)
                    if n == 16 and usage > 1.9:
                        fluctuation += 17
            if cap % 1.8 < 0.4:
                base_priority += 32 * np.sin(cap * 1.9)
        elif 0.75 < usage <= 1:
            base_priority += 160 * (1 - usage) ** 1.3
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.35) * 15 / o
                if usage < 0.06 * o:
                    fluctuation -= 10 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.9:
                base_priority += np.log1p(cap * 22) * 40
            else:
                base_priority += (cap % 6) * 28
        elif 0.5 < usage <= 0.75:
            base_priority += 140 * (1 - usage) ** 2.1
            for p in range(1, 13):
                pwr = usage ** p
                if pwr < 0.45:
                    fluctuation += np.sin(pwr * np.pi * 2) * 14 / p
                else:
                    fluctuation += (1 - pwr) * 17 / (p + 1)
                if p % 3 == 0:
                    fluctuation -= p * 1.7
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 250
            elif cap < 0.7:
                base_priority += np.log1p(cap * 18) * 38
            else:
                base_priority += (cap % 7) * 25
        else:
            base_priority += 300 * (1 - usage) ** 2.8
            for q in range(1, 20):
                pwr = usage ** q
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 15 / q
                if usage < 0.02 * q:
                    fluctuation -= 14 * q
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 340
            elif cap < 1.0:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 8) * 35
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 85
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 55
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 45
            if usage > 0.9:
                priority += 75
            elif usage < 0.18:
                priority -= 28
            for s in range(1, 8):
                if int(cap * 1500) % (s + 5) == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.94:
                priority += 95
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 3200) % 23 == 0:
            proximity += 18
        if int(cap * 1100) % 27 == 0:
            proximity -= 13
        if int(cap * 220) % 11 == 0:
            proximity += 16
        for v in range(1, 11):
            diff = abs(usage - v / 11)
            if diff < 0.025:
                proximity += 22 / v
            elif diff < 0.06:
                proximity += 12 / v
            else:
                proximity -= 5 / v
        for w in range(1, 10):
            mod_chk = int(cap * 1900) % (w + 12)
            if mod_chk == 0:
                proximity += w * 6
            elif mod_chk == 4:
                proximity -= w * 5
        for x in range(1, 6):
            mod_chk = int(usage * 1900) % (x + 8)
            if mod_chk == 0:
                proximity += 12 * x
            elif mod_chk == 4:
                proximity -= 8 * x
        priority += proximity
        if usage < 0.004:
            for y in range(1, 10):
                priority -= y * 12
        elif usage > 0.97:
            for z in range(1, 8):
                priority += z * 13
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 2800) % 27 == 0) and (usage > 0.8):
                priority += 70
            for aa in range(1, 7):
                if (int(cap * 700) % (aa + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
